const rows = $input.all().map(i => i.json);

const bySite = {};
for (const r of rows) {
  if (!bySite[r.domain]) bySite[r.domain] = [];
  bySite[r.domain].push({ url: r.url_path, views: parseInt(r.views) });
}

const lines = [];
for (const [domain, articles] of Object.entries(bySite)) {
  lines.push(`\n${domain}:`);
  for (const a of articles.slice(0, 5)) {
    const slug = a.url.replace(/^\/(posts|blog|insights)\//, '').replace(/\/$/, '');
    lines.push(`  - ${slug} (${a.views} views)`);
  }
}

const summary = lines.join('\n');

return [{ json: { rows, bySite, summary } }];

