const groqResp = $input.first().json;
const raw = groqResp.choices[0].message.content;

let insights = {};
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) insights = JSON.parse(jsonMatch[0]);
} catch(e) {
  insights = { raw };
}

const prev = $('Format Data').first().json;

const output = {
  generated_at: new Date().toISOString(),
  week: new Date().toISOString().slice(0, 10),
  top_articles: prev.bySite,
  insights: insights.insights || insights
};

return [{ json: output }];

const d = $('Build Insights').first().json;
const bySite = d.top_articles;
const insights = d.insights;

let articleLines = [];
for (const [domain, articles] of Object.entries(bySite)) {
  const shortDomain = domain.replace('.com', '').replace('the', '');
  articleLines.push(`<b>${domain}</b>`);
  for (const a of (articles || []).slice(0, 3)) {
    const slug = a.url.replace(/^\/(posts|blog|insights)\//, '').replace(/\/$/, '').replace(/-/g, ' ');
    articleLines.push(`  ${a.views} views – ${slug}`);
  }
}

let insightLines = [];
for (const [domain, data] of Object.entries(insights)) {
  if (data && data.suggested_keywords) {
    insightLines.push(`<b>${domain}:</b> ` + data.suggested_keywords.slice(0, 3).join(', '));
  }
}

const text = '<b>Content Performance – veckorapport</b>\n\n' +
  '<b>Toppinnehall denna vecka:</b>\n' +
  '<code>' + articleLines.join('\n') + '</code>\n\n' +
  '<b>Foreslagna keywords nasta vecka:</b>\n' +
  insightLines.join('\n');

return [{ json: { text } }];

